SELECT COUNT(*) 
FROM user_api_keys
WHERE api_key_expiration BETWEEN datetime('now') AND datetime('now', '+30 days');

SELECT custom_unit_id 
FROM custom_units 
WHERE custom_name = 'myCustomUnit';

SELECT u.unit_name, bu.base_unit_name
FROM units u
JOIN base_units bu ON u.base_unit_id = bu.base_unit_id;

SELECT user_id, unit_id
FROM unit_comments
WHERE comment LIKE '%understand%';

SELECT unit_name, symbol
FROM units
WHERE unit_id IN (
  SELECT from_unit_id
  FROM conversion_factors
  WHERE to_unit_id = (
    SELECT unit_id FROM units WHERE unit_name = 'meter'
  )
);

SELECT user_id
FROM unit_comments
WHERE comment_date = (
  SELECT MIN(comment_date)
  FROM unit_comments
);
